export async function pull(flags = {}) {
  const config = resolveConfig(flags);

  // --symbols bypasses the FMP screener with a pre-seeded list (e.g. from a RelVol screen).
  // relVolMin and minScore are zeroed so seed tickers aren't dropped by filters tuned for
  // screener-universe noise reduction.
  const symbolSeed = flags.symbols
    ? String(flags.symbols).split(',').map(s => s.trim().toUpperCase()).filter(Boolean)
    : null;

  if (symbolSeed) {
    config.relVolMin  = 0;
    config.minScore   = 0;
  }

  let universe;
  if (symbolSeed) {
    console.log(`QCPM Strategy Search: pre-seeded ${symbolSeed.length} symbol(s) via --symbols`);
    universe = symbolSeed.map(s => ({ symbol: s }));
  } else {
    const screenerParams = {
      marketCapMoreThan: config.marketCapMin,
      priceMoreThan: config.priceMin,
      volumeMoreThan: config.volumeMin,
      country: flags.country ?? 'US',
      isActivelyTrading: 'true',
      limit: config.universeLimit,
    };
    console.log(
      `QCPM Strategy Search: universe ${config.universeLimit}, ` +
      `price > $${config.priceMin}, avg dollar volume > ${formatCompact(config.minDollarVolume)}`
    );
    const base = await screenStocks(screenerParams);
    universe = Array.isArray(base) ? base.filter(row => row?.symbol) : [];
    console.log(`  FMP screener returned ${universe.length} symbol(s). Fetching batch quotes...`);
  }
  const quotes   = await fetchBatchQuotes(universe.map(row => row.symbol));
  const quoteMap = new Map(quotes.map(q => [String(q?.symbol || '').toUpperCase(), q]));
  console.log(`  Batch quotes returned ${quoteMap.size} symbol(s). Enriching daily filters...`);

