/**
 * month-end-cleanup.mjs — Monthly vault rollup + archive
 *
 * Reads frontmatter from every YYYY-MM-DD_*.md in 05_Data_Pulls/{Domain}/
 * for the target month, builds a cross-domain progression summary note, then
 * moves the daily files into 05_Data_Pulls/_archive/YYYY-MM/{Domain}/.
 *
 * Usage:
 *   node run.mjs system month-end
 *   node run.mjs system month-end --month 2026-03
 *   node run.mjs system month-end --dry-run
 *   node run.mjs system month-end --skip-archive
 *   node run.mjs system month-end --skip-summary
 */

import { readdirSync, readFileSync, mkdirSync, renameSync } from 'fs';
import { join } from 'path';
import { getPullsDir } from '../lib/config.mjs';
import { buildNote, buildTable, writeNote } from '../lib/markdown.mjs';

const STATUS_RANK = Object.freeze({ alert: 2, watch: 1, clear: 0 });

export async function run(flags = {}) {
  const dryRun      = Boolean(flags['dry-run']);
  const skipArchive = Boolean(flags['skip-archive']);
  const skipSummary = Boolean(flags['skip-summary']);
  const month       = resolveMonth(flags.month);
  const monthLabel  = formatMonthLabel(month);

  const pullsDir   = getPullsDir();
  const archiveDir = join(pullsDir, '_archive', month);

  console.log(`Month-end cleanup: ${monthLabel} (${month})`);
  if (dryRun) console.log('  [dry-run] No files will be moved or written.');

  // Collect every YYYY-MM-DD_*.md for the target month across all domain folders
  const domainDirs = readdirSync(pullsDir, { withFileTypes: true })
    .filter(e => e.isDirectory() && !e.name.startsWith('_'))
    .map(e => e.name)
    .sort();

  const allFiles = [];
  for (const domain of domainDirs) {
    const domainDir = join(pullsDir, domain);
    try {
      const files = readdirSync(domainDir)
        .filter(f => f.endsWith('.md') && f.startsWith(month))
        .sort()
        .map(f => ({ domain, filename: f, path: join(domainDir, f) }));
      allFiles.push(...files);
    } catch {
      // skip unreadable subdirectories
    }
  }

  if (allFiles.length === 0) {
    console.log(`  No files found for ${month}.`);
    return;
  }

  const domainCount = new Set(allFiles.map(f => f.domain)).size;
  console.log(`  Found ${allFiles.length} file(s) across ${domainCount} domain(s).`);

  const parsedFiles = allFiles.map(f => ({ ...f, meta: parseFrontmatter(f.path) }));
  const byDomain    = groupBy(parsedFiles, f => f.domain);

  // Write monthly rollup note
  if (!skipSummary) {
    if (!dryRun) mkdirSync(archiveDir, { recursive: true });
    const rollupContent = buildMonthlyRollup({ byDomain, month, monthLabel });
    const rollupPath    = join(archiveDir, `${month}_Monthly_Rollup.md`);
    if (!dryRun) writeNote(rollupPath, rollupContent);
    console.log(`  ${dryRun ? '[dry-run] would write rollup →' : 'Wrote rollup →'} ${rollupPath}`);
  }

  // Archive daily files
  if (!skipArchive) {
    for (const file of allFiles) {
      const destDir  = join(archiveDir, file.domain);
      const destPath = join(destDir, file.filename);
      if (!dryRun) {
        mkdirSync(destDir, { recursive: true });
        renameSync(file.path, destPath);
      } else {
        console.log(`  [dry-run] would move: ${file.domain}/${file.filename}`);
      }
    }
    const verb = dryRun ? 'Would archive' : 'Archived';
    console.log(`\n  ${verb} ${allFiles.length} file(s) → _archive/${month}/`);
  }
}

// ── helpers ───────────────────────────────────────────────────────────────────

function resolveMonth(monthFlag) {
  if (monthFlag) return String(monthFlag).trim();
  const now  = new Date();
  const prev = new Date(now.getFullYear(), now.getMonth() - 1, 1);
  return `${prev.getFullYear()}-${String(prev.getMonth() + 1).padStart(2, '0')}`;
}

function formatMonthLabel(month) {
  const [year, mon] = month.split('-').map(Number);
  return new Date(year, mon - 1, 1).toLocaleString('en-US', { month: 'long', year: 'numeric' });
}

function parseFrontmatter(filePath) {
  try {
    const content = readFileSync(filePath, 'utf8');
    const match   = content.match(/^---\n([\s\S]*?)\n---/);
    if (!match) return {};
    const out = {};
    for (const line of match[1].split('\n')) {
      const colon = line.indexOf(':');
      if (colon === -1) continue;
      const key = line.slice(0, colon).trim();
      let   val = line.slice(colon + 1).trim();
      if ((val.startsWith('"') && val.endsWith('"')) ||
          (val.startsWith("'") && val.endsWith("'"))) {
        val = val.slice(1, -1);
      }
      out[key] = val;
    }
    return out;
  } catch {
    return {};
  }
}

function groupBy(arr, keyFn) {
  const map = new Map();
  for (const item of arr) {
    const k = keyFn(item);
    if (!map.has(k)) map.set(k, []);
    map.get(k).push(item);
  }
  return map;
}

function reportType(filename) {
  // "2026-04-29_Agent_Analysis_AAPL.md" → "Agent Analysis AAPL"
  return filename
    .replace(/^\d{4}-\d{2}-\d{2}_/, '')
    .replace(/\.md$/, '')
    .replace(/_/g, ' ');
}

function signalTrend(statuses) {
  if (statuses.length < 2) return '—';
  const first = STATUS_RANK[statuses[0]]      ?? -1;
  const last  = STATUS_RANK[statuses.at(-1)]  ?? -1;
  if (last > first) return '↑ escalating';
  if (last < first) return '↓ settling';
  return '→ stable';
}

function buildMonthlyRollup({ byDomain, month, monthLabel }) {
  const allParsed    = [...byDomain.values()].flat();
  const totalFiles   = allParsed.length;
  const totalAlerts  = allParsed.filter(f => f.meta.signal_status === 'alert').length;
  const totalWatches = allParsed.filter(f => f.meta.signal_status === 'watch').length;

  const sections = [
    {
      heading: 'Summary',
      content: buildTable(
        ['Metric', 'Value'],
        [
          ['Month',             monthLabel],
          ['Total files',       String(totalFiles)],
          ['Domains covered',   String(byDomain.size)],
          ['Alert-status days', String(totalAlerts)],
          ['Watch-status days', String(totalWatches)],
          ['Clear-status days', String(totalFiles - totalAlerts - totalWatches)],
        ]
      ),
    },
  ];

  for (const [domain, files] of [...byDomain.entries()].sort()) {
    const byType = groupBy(files, f => reportType(f.filename));
    const rows   = [];

    for (const [type, typeFiles] of [...byType.entries()].sort()) {
      const sorted   = [...typeFiles].sort((a, b) => a.filename.localeCompare(b.filename));
      const statuses = sorted.map(f => f.meta.signal_status).filter(Boolean);
      const alerts   = statuses.filter(s => s === 'alert').length;
      const watches  = statuses.filter(s => s === 'watch').length;
      const last     = statuses.at(-1) ?? '—';
      rows.push([type, String(sorted.length), String(alerts), String(watches), last, signalTrend(statuses)]);
    }

    sections.push({
      heading: `${domain} (${files.length} files)`,
      content: buildTable(
        ['Report Type', 'Runs', 'Alerts', 'Watches', 'Last Status', 'Trend'],
        rows
      ),
    });
  }

  return buildNote({
    frontmatter: {
      title:           `Monthly Rollup — ${monthLabel}`,
      month,
      domain:          'all',
      data_type:       'monthly_rollup',
      frequency:       'monthly',
      total_files:     totalFiles,
      total_alerts:    totalAlerts,
      domains_covered: byDomain.size,
      tags:            ['monthly-rollup', 'vault-cleanup'],
    },
    sections,
  });
}

